const body = $input.first().json.body || $input.first().json;
const weekStartDate = body.weekStartDate || new Date().toISOString().split('T')[0];
const businessContext = body.businessContext || 'A solo service provider business';

const prompt = `You are a content strategist for solo service providers and freelancers.

Business context: ${businessContext}
Week starting: ${weekStartDate}

Generate a 7-day content plan for this business. For each day, create:
1. A topic/theme relevant to solo service providers
2. An Instagram caption (engaging, with 3-5 relevant hashtags, under 150 words)
3. A LinkedIn post (professional, thought-leadership tone, 100-200 words)
4. A blog opener paragraph (informative, hooks the reader, 60-80 words)

Return ONLY valid JSON in this exact format:
{
  "posts": [
    {
      "content_date": "YYYY-MM-DD",
      "day_number": 1,
      "topic": "Topic title",
      "instagram_caption": "Caption text with #hashtags",
      "linkedin_post": "LinkedIn post text",
      "blog_opener": "Blog opening paragraph",
      "tags": ["tag1", "tag2"],
      "status": "Generated"
    }
  ]
}

Generate all 7 days starting from ${weekStartDate}. Make each day's content unique and valuable.`;

return [{ json: { prompt, weekStartDate } }];

const raw = $input.first().json.message?.content || $input.first().json.content || '{}';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { posts: [] };
}
return [{ json: parsed }];
